"""Domain models for the web API."""
from typing import List, Optional


class Customer:
    """A customer who can place orders."""

    def __init__(self, customer_id: int, name: str, email: str):
        self._id = customer_id
        self.name = name
        self.email = email
        self._orders: List['Order'] = []

    @property
    def pk(self) -> int:
        return self._id

    @property
    def orders(self) -> List['Order']:
        return list(self._orders)

    def add_order(self, order: 'Order'):
        self._orders.append(order)

    def to_dict(self) -> dict:
        return {
            'id': self._id,
            'name': self.name,
            'email': self.email,
        }

    def validate(self) -> bool:
        return bool(self.name) and '@' in self.email

    def __eq__(self, other):
        if not isinstance(other, Customer):
            return NotImplemented
        return self._id == other._id

    def __hash__(self):
        return hash(self._id)

    def __repr__(self):
        return f'Customer(id={self._id}, name={self.name!r})'


class LineItem:
    """A single line item in an order."""

    def __init__(self, item_id: int, product_name: str, quantity: int, unit_price: float):
        self._id = item_id
        self.product_name = product_name
        self.quantity = quantity
        self.unit_price = unit_price

    @property
    def pk(self) -> int:
        return self._id

    @property
    def total(self) -> float:
        return self.quantity * self.unit_price

    def to_dict(self) -> dict:
        return {
            'id': self._id,
            'product_name': self.product_name,
            'quantity': self.quantity,
            'unit_price': self.unit_price,
            'total': self.total,
        }

    def validate(self) -> bool:
        return self.quantity > 0 and self.unit_price >= 0

    def __eq__(self, other):
        if not isinstance(other, LineItem):
            return NotImplemented
        return self._id == other._id

    def __hash__(self):
        return hash(self._id)

    def __repr__(self):
        return f'LineItem(id={self._id}, product={self.product_name!r})'


class Order:
    """An order containing line items, belonging to a customer."""

    def __init__(self, order_id: int, customer: Customer, line_items: Optional[List[LineItem]] = None, status: str = 'pending'):
        self._id = order_id
        self.customer = customer
        self.line_items = list(line_items) if line_items else []
        self.status = status

    @property
    def pk(self) -> int:
        return self._id

    @property
    def total(self) -> float:
        return sum(item.total for item in self.line_items)

    def add_item(self, item: LineItem):
        self.line_items.append(item)

    def to_dict(self) -> dict:
        return {
            'id': self._id,
            'customer': self.customer.to_dict(),
            'line_items': [item.to_dict() for item in self.line_items],
            'status': self.status,
            'total': self.total,
        }

    def validate(self) -> bool:
        return (
            self.customer.validate()
            and all(item.validate() for item in self.line_items)
            and self.status in ('pending', 'confirmed', 'shipped', 'delivered', 'cancelled')
        )

    def __eq__(self, other):
        if not isinstance(other, Order):
            return NotImplemented
        return self._id == other._id

    def __hash__(self):
        return hash(self._id)

    def __repr__(self):
        return f'Order(id={self._id}, status={self.status!r}, items={len(self.line_items)})'

