"""Database layer with in-memory storage.

Currently creates full model objects on every query, which is slow
for high-traffic scenarios.
"""
from typing import Optional, List, Dict, Any
from models import Order, Customer, LineItem


class CustomerRepository:
    """Repository for Customer objects."""

    def __init__(self):
        self._storage: Dict[int, dict] = {}
        self._next_id = 1

    def create(self, data: dict) -> Customer:
        customer_id = self._next_id
        self._next_id += 1
        self._storage[customer_id] = {
            'customer_id': customer_id,
            'name': data['name'],
            'email': data['email'],
        }
        return self._build_object(customer_id)

    def get(self, customer_id: int) -> Optional[Customer]:
        if customer_id not in self._storage:
            return None
        return self._build_object(customer_id)

    def list(self) -> List[Customer]:
        return [self._build_object(cid) for cid in self._storage]

    def update(self, customer_id: int, data: dict) -> Optional[Customer]:
        if customer_id not in self._storage:
            return None
        stored = self._storage[customer_id]
        stored.update({k: v for k, v in data.items() if k != 'customer_id'})
        return self._build_object(customer_id)

    def delete(self, customer_id: int) -> bool:
        if customer_id in self._storage:
            del self._storage[customer_id]
            return True
        return False

    def _build_object(self, customer_id: int) -> Customer:
        """Construct a Customer model from stored data. Expensive."""
        row = self._storage[customer_id]
        return Customer(
            customer_id=row['customer_id'],
            name=row['name'],
            email=row['email'],
        )


class OrderRepository:
    """Repository for Order objects."""

    def __init__(self, customer_repo: CustomerRepository):
        self._storage: Dict[int, dict] = {}
        self._next_id = 1
        self._customer_repo = customer_repo

    def create(self, data: dict) -> Order:
        order_id = self._next_id
        self._next_id += 1
        self._storage[order_id] = {
            'order_id': order_id,
            'customer_id': data['customer_id'],
            'line_items': data.get('line_items', []),
            'status': data.get('status', 'pending'),
        }
        return self._build_object(order_id)

    def get(self, order_id: int) -> Optional[Order]:
        if order_id not in self._storage:
            return None
        return self._build_object(order_id)

    def list(self) -> List[Order]:
        return [self._build_object(oid) for oid in self._storage]

    def update(self, order_id: int, data: dict) -> Optional[Order]:
        if order_id not in self._storage:
            return None
        stored = self._storage[order_id]
        stored.update({k: v for k, v in data.items() if k != 'order_id'})
        return self._build_object(order_id)

    def delete(self, order_id: int) -> bool:
        if order_id in self._storage:
            del self._storage[order_id]
            return True
        return False

    def _build_object(self, order_id: int) -> Order:
        """Construct an Order model from stored data. Expensive."""
        row = self._storage[order_id]
        customer = self._customer_repo.get(row['customer_id'])
        line_items = []
        for idx, item_data in enumerate(row['line_items']):
            line_items.append(LineItem(
                item_id=item_data.get('item_id', idx + 1),
                product_name=item_data['product_name'],
                quantity=item_data['quantity'],
                unit_price=item_data['unit_price'],
            ))
        return Order(
            order_id=row['order_id'],
            customer=customer,
            line_items=line_items,
            status=row['status'],
        )

