from db import OrderRepository, CustomerRepository
from serializers import OrderSerializer, CustomerSerializer
from models import Order


class OrderAPI:
    """API endpoints for orders."""

    def __init__(self):
        self.customer_repo = CustomerRepository()
        self.order_repo = OrderRepository(self.customer_repo)

    def create_order(self, customer_data: dict, items_data: list) -> dict:
        """Create a new order with customer and line items."""
        customer = self.customer_repo.create(customer_data)
        order = self.order_repo.create({
            'customer_id': customer.pk,
            'line_items': items_data,
        })
        return OrderSerializer.serialize(order)

    def get_order_detail(self, order_id: int) -> dict:
        """Get full order details."""
        order = self.order_repo.get(order_id)
        if order is None:
            return {'error': 'not found'}
        # Direct attribute access - depends on Order type
        customer_name = order.customer.name
        order_pk = order.pk
        return {
            'data': OrderSerializer.serialize(order),
            'meta': {
                'customer_name': customer_name,
                'order_pk': order_pk,
                'item_count': len(order.line_items),
            },
        }

    def list_orders(self) -> list:
        """List all orders."""
        orders = self.order_repo.list()
        return [OrderSerializer.serialize(o) for o in orders]

    def update_order_status(self, order_id: int, new_status: str) -> dict:
        """Update order status."""
        order = self.order_repo.update(order_id, {'status': new_status})
        if order is None:
            return {'error': 'not found'}
        return OrderSerializer.serialize(order)

    def get_raw_order(self, order_id: int):
        """Get the raw Order object (used internally)."""
        return self.order_repo.get(order_id)

